class IselContext:
  def __init__(self, sink:UOp):
    self.uses = consumer_map_from_toposort(sink.toposort())
    self.reg_n = itertools.count()
    def arg_key(u:UOp):
      if u.op is Ops.SPECIAL: return (2, u.arg)
